UPDATE businesses SET primary_category='food_dining', subcategory='cafe', business_description='AT Oasis Coffee And Tea Shop is a specialty cafe located in Phoenix, Arizona. The shop is known for its exclusive import of Ethiopian specialty coffee from the Sidamo and Yirgacheffe regions. The owner, Aisha Tedros, personally tests each crop to ensure the quality and authenticity of the coffee. In addition to coffee, the shop also offers tea, baked goods, and savory treats. They also provide an online store for customers to shop for their coffee selection from home and offer a membership program for regular customers. The shop is highly rated for its quality products, friendly staff, and unique Ethiopian coffee experience.', products_services='["Ethiopian specialty coffee","Tea","Baked goods","Savory treats","Online store","Membership program"]', keywords='Ethiopian specialty coffee, Sidamo, Yirgacheffe, Aisha Tedros, online store, membership program, Phoenix, Arizona', enrichment_status='completed', enrichment_date='2025-08-24T10:06:28.196Z', enrichment_source='firecrawl', business_attributes='{"locally_owned":true,"specialty_focus":"Ethiopian specialty coffee"}' WHERE id='0225939d-ed42-418b-90ca-e95d968e1bb4';
