UPDATE businesses SET primary_category='retail_shopping', subcategory='grocery_market', business_description='Boyd''s Farm is a family-owned farm and grocery market located in Tonto Basin, Arizona. They specialize in producing and selling homemade and farm-fresh products. Their offerings include a variety of jellies, jams, butters, honey, and elderberry tonic. They also sell fruit trees. The farm prides itself on its green thumb, with the ability to make anything grow and thrive. They gather or grow over half the fruits used in all their jellies and jams. They are known for their unique flavors and flavor combinations, and their dedication to providing healthy, tasty products.', products_services='["Jelly","Jam","Butters","Honey","Elderberry Tonic","Fruit Trees"]', keywords='Boyd''s Farm, homemade products, farm fresh, jellies, jams, butters, honey, elderberry tonic, fruit trees, Arizona farm', enrichment_status='completed', enrichment_date='2025-08-24T10:42:00.257Z', enrichment_source='firecrawl', business_attributes='{"locally_owned":true,"specialty_focus":"Homemade and farm fresh products"}' WHERE id='1278298e-9aff-4491-9124-ab6fed60ec6d';
