UPDATE businesses SET primary_category='food_dining', subcategory='bakery', business_description='Bread Brothers Bakery is a bakery business located in Mesa, Arizona, specializing in a variety of breads and baked goods. They serve people with a love for fresh, homemade breads and pastries. The bakery distinguishes itself by offering a wide range of products made from 100% whole grain flour from non-GMO, pesticide-free wheat, emphasizing their commitment to clean food. Their offerings include sandwich bread, sourdough bread, focaccia, bagels, cinnamon rolls, cookies, brownies, croissants, granola, muffins, pizza crust, and buns. They also sell baking mixes, cereals, and kitchen equipment.', products_services='["Sandwich Bread","Sourdough Bread","Focaccia","Bagels","Cinnamon Rolls","Cookies","Brownies","Croissants","Granola","Muffins","Pizza Crust","Buns","Baking Mixes","Cereal","Kitchen Equipment"]', keywords='bakery, bread, whole grain, non-GMO, clean food, Arizona, Bread Brothers Bakery', enrichment_status='completed', enrichment_date='2025-08-25T00:13:44.348Z', enrichment_source='improved_firecrawl', business_attributes='{"locally_owned":true,"specialty_focus":"Whole grain, non-GMO, clean food baking"}' WHERE id='214ba21f-b83d-4d52-887c-b16bea8866e6';
