UPDATE businesses SET primary_category='retail_shopping', subcategory='grocery_market', business_description='Bridle Path Beeyard is a local beekeeping business based in Phoenix, Arizona. Established in 2016, it focuses on urban beekeeping, promoting pollination, and infusing the genetics of gentle honeybees into the feral honeybee populations. The business offers pure, natural Arizona honey collected from the gardens, trees, and landscapes of Central Phoenix. The honeybees are treated with utmost care and meticulous attention to detail, allowing the colonies to thrive in their natural environment. The business also supports the local beekeeping community by reinvesting a large portion of its revenues back into the colonies for scientific monitoring equipment, enrollment in disease surveillance programs, and other efforts to keep the bees healthy and happy.', products_services='["Local Honey","Beekeeping","Pollination Services"]', keywords='local honey, beekeeping, natural Arizona honey, urban beekeeping, pollination, honeybees, sustainable beekeeping', enrichment_status='completed', enrichment_date='2025-08-25T00:38:19.609Z', enrichment_source='improved_firecrawl', business_attributes='{"locally_owned":true,"specialty_focus":"Urban Beekeeping and Local Honey Production"}' WHERE id='2c74c74f-a7bd-4088-b844-6a6a0748e6f8';
