UPDATE businesses SET primary_category='beauty_personal_care', subcategory='hair_salon', business_description='Cloud 9 Salon Spa is a beauty and personal care business located in Tempe, Arizona. They offer a wide range of services including haircuts, hair coloring, hair styling, and other salon services. In addition, they also provide spa services such as Swedish massage, therapeutic massage, hot stone therapy, and microblading. Their team of skilled stylists and professionals are dedicated to providing exceptional beauty and hair treatments. They distinguish themselves by providing a sophisticated salon ambiance, tailored beauty solutions, and a commitment to quality service.', products_services='["Hair Cuts","Hair Color","Hair Styling","Swedish Massage","Therapeutic Massage","Hot Stone Therapy","Microblading"]', keywords='Hair Salon, Spa, Haircuts, Hair Coloring, Hair Styling, Swedish Massage, Therapeutic Massage, Hot Stone Therapy, Microblading', enrichment_status='completed', enrichment_date='2025-08-25T00:52:33.619Z', enrichment_source='improved_firecrawl', business_attributes='{"locally_owned":true,"specialty_focus":"Hair and Spa Services"}' WHERE id='32cdbe22-8b31-4365-9d0a-4cdee72a8a08';
