UPDATE businesses SET primary_category='retail_shopping', subcategory='grocery_market', business_description='Desert Mountain Moringa and Microgreens is a unique grocery market business based in Clarkdale, Arizona. They specialize in the cultivation and sale of Moringa and Microgreens, serving health-conscious individuals and those interested in organic, nutrient-rich food options. The business distinguishes itself by offering locally grown, organic products that are never sprayed with pesticides. They also provide educational resources about the Moringa tree and its benefits for wellness and health. Customers can purchase their products online or at local markets that the business attends several times a week.', products_services='["Moringa","Microgreens","Nursery Supply","BioStimulant"]', keywords='Moringa, Microgreens, organic, locally grown, health, wellness, nursery supply, Arizona', enrichment_status='completed', enrichment_date='2025-08-25T00:14:40.332Z', enrichment_source='improved_firecrawl', business_attributes='{"locally_owned":true,"specialty_focus":"Moringa and Microgreens cultivation and sale"}' WHERE id='21737948-6570-4510-b62d-271359c86a79';
