UPDATE businesses SET primary_category='nonprofit_community', subcategory='community_center', business_description='Keeling Garden (Midtown) is a community garden located in Tucson, Arizona. It provides a space for community members to engage in gardening activities, fostering a sense of community and promoting sustainable practices. The garden hosts various events such as Community Dinner, where attendees are encouraged to bring a dish and mingle with other community members. They also offer plot rentals and reservations for those interested in starting their own garden. Keeling Garden distinguishes itself by recognizing the historical injustices perpetrated upon the Indigenous people of the Tucson Basin and honoring their cultures and contributions.', products_services='["Community Dinner","Plot Rentals and Reservations","Start a New Garden"]', keywords='community garden, plot rentals, community dinner, sustainable practices, Tucson, gardening', enrichment_status='completed', enrichment_date='2025-08-25T00:27:55.862Z', enrichment_source='improved_firecrawl', business_attributes='{"locally_owned":true,"specialty_focus":"Community engagement through gardening"}' WHERE id='287e976d-bcb5-4e6c-aceb-178f7dc95caf';
