UPDATE businesses SET primary_category='nonprofit_community', subcategory='community_center', business_description='Las Milpitas Community Farm is a non-profit community center that focuses on promoting sustainable local food systems. Situated on a six-acre land in Tucson, Arizona, it provides materials, education, and support for local residents to grow food for themselves, with a particular emphasis on assisting low-income families. The farm serves as a unique community-building space where neighbors can gather, connect, learn, and share. Through workshops, work days, and partnerships with local schools, it also operates as an educational site that trains and builds leaders in desert food cultivation. The farm is part of the Community Food Bank of Southern Arizona and aims to bring residents from all areas of Tucson together to build community and create strong leaders who can advocate for a resilient, sustainable local food system.', products_services='["Community farming","Educational workshops","Gardening space","Leadership training","Community events hosting"]', keywords='community farm, sustainable local food system, desert food cultivation, low-income families support, educational site, community building', enrichment_status='completed', enrichment_date='2025-08-24T10:39:13.812Z', enrichment_source='firecrawl', business_attributes='{"locally_owned":true,"specialty_focus":"Promoting sustainable local food systems and community building"}' WHERE id='1115bb76-6e25-44aa-8d36-5069a1ef1b40';
