UPDATE businesses SET primary_category='food_dining', subcategory='brewery_winery', business_description='Lawrence Dunham Vineyards is a winery located in the Chiricahua Mountain foothills in Southeastern Arizona. They offer a variety of award-winning wines that are a direct reflection of the unique high-altitude terroir. The winery distinguishes itself by providing easy to apply wine tips to expand customers'' wine and food enjoyment. They also offer wine tasting experiences and have a wine club that customers can join. The business is named after the family names Lawrence and Dunham, with the V denoting their vineyard.', products_services='["Wine tasting","Wine club membership","Wine shop"]', keywords='winery, wine tasting, wine club, award-winning wines, high-altitude terroir, wine tips', enrichment_status='completed', enrichment_date='2025-08-24T23:57:05.723Z', enrichment_source='firecrawl', business_attributes='{"locally_owned":true,"specialty_focus":"High-altitude terroir wines"}' WHERE id='1d9af38b-aa13-4ca3-8672-731dc6eac1e1';
