UPDATE businesses SET primary_category='health_wellness', subcategory='alternative_medicine', business_description='Paige Artists Studio Gallery, run by Susan Paige, OMC, LMT, is an alternative medicine business with a variety of offerings serving people seeking holistic and spiritual healing. With over 40 years of experience, Susan offers a range of workshops, classes, and sessions in Reiki Healing, Intuitive Sessions, Essential Oils, Aromatherapy, and more. She also provides personal and spiritual growth workshops and energy awareness workshops. Additionally, Susan is an ordained minister and offers services for marriage, unions, and other life ceremonies. The business distinguishes itself by offering a wide range of holistic healing services, personal growth workshops, and life ceremonies.', products_services='["Reiki Healing","Intuitive Sessions","Essential Oils","Aromatherapy Classes","Personal/Spiritual Growth Workshops","Energy Awareness Workshop","Marriage, Unions, and Life Ceremonies"]', keywords='Reiki Healing, Intuitive Sessions, Essential Oils, Aromatherapy, Personal/Spiritual Growth Workshops, Energy Awareness Workshop, Marriage Ceremonies, Life Ceremonies', enrichment_status='completed', enrichment_date='2025-08-25T00:03:32.569Z', enrichment_source='improved_firecrawl', business_attributes='{"locally_owned":true,"specialty_focus":"Holistic Healing and Personal/Spiritual Growth"}' WHERE id='108fd112-6449-4c59-bddb-a84d2f186e23';
UPDATE businesses SET primary_category='arts_entertainment', subcategory='recreation', business_description='Paint On Me is a face and body painting business based in Phoenix, Arizona, offering a variety of services for different events. They serve people looking to add a unique and fun element to their parties, gatherings, or events. They distinguish themselves by providing face painting services for a variety of occasions, including birthday parties, church functions, fairs & festivals, school events, company functions, and more. They also offer UV/Black Light cosmic face painting, adding a unique twist to their service. Their services are not limited to children''s parties but also extend to adult events like costume contests and masquerade balls.', products_services='["Face/Body Painting","Cosmic face painting (UV/Black Light)","Event entertainment"]', keywords='face painting, body painting, party entertainment, event services, cosmic face painting, UV/Black Light painting', enrichment_status='completed', enrichment_date='2025-08-24T10:21:44.968Z', enrichment_source='firecrawl', business_attributes='{"locally_owned":true,"specialty_focus":"Face and body painting for various events"}' WHERE id='08411de5-858a-4e25-a402-3e0b3dd20fe3';
