UPDATE businesses SET primary_category='nonprofit_community', subcategory='nonprofit_org', business_description='Stardust Building Supplies is a nonprofit organization based in Arizona that specializes in providing affordable, reclaimed building supplies to the community. Serving over 3,000 people every month, they are committed to sustainability and waste reduction by repurposing materials that would otherwise end up in landfills. They offer deconstruction services, home pickups, and accept material donations. Additionally, they provide a platform for shoppers and contractors to purchase or donate materials. Their mission is driven by a vision of a world without waste, and they have successfully diverted over 100 million pounds of usable material from the landfill since their inception in 1997.', products_services='["Deconstruction Services","Home Pickup","Material Donation","Gifts In Kind","Triple R Certification"]', keywords='reclaimed building supplies, deconstruction services, home pickup, material donation, sustainability, waste reduction, nonprofit', enrichment_status='completed', enrichment_date='2025-08-24T10:29:30.857Z', enrichment_source='firecrawl', business_attributes='{"locally_owned":true,"specialty_focus":"Reusing and repurposing building materials to reduce waste and support sustainability"}' WHERE id='0c262c60-3d17-4f08-b281-e3431b477ff7';
