UPDATE businesses SET primary_category='arts_entertainment', subcategory='recreation', business_description='Superstition Mountain Lost Dutchman Museum is a unique recreational and educational facility located in Apache Junction, Arizona. It serves as a cultural hub for locals and tourists interested in the rich history and mysteries of the Superstition Mountains. The museum distinguishes itself by offering a wide array of exhibits, lectures, and tours. It also houses the Elvis Chapel and a Stamp Mill, adding to its diverse offerings. The museum is currently closed for renovations and will reopen in 2025.', products_services='["Exhibits","Events","Grounds Tours","Lectures","Museum Shop","Membership","Rentals"]', keywords='museum, Superstition Mountains, history, recreation, Apache Junction, Elvis Chapel, Stamp Mill', enrichment_status='completed', enrichment_date='2025-08-24T10:37:20.661Z', enrichment_source='firecrawl', business_attributes='{"locally_owned":true,"specialty_focus":"Superstition Mountains history and mysteries"}' WHERE id='103e29ca-c612-4218-90ff-ed0256108deb';
