UPDATE businesses SET primary_category='technology', subcategory='it_support', business_description='UniTech Incorporated is a technology-based business specializing in telecommunications equipment and systems. They serve businesses of all sizes, particularly those in need of support with VOIP or SIP platforms, structured cabling, and Avaya IP Office systems. Their unique selling point is their comprehensive support, from sales to service, for both legacy and modern telecommunication systems. With experienced technicians spread throughout Maricopa County, Pinal, and Pima, Arizona, they assure prompt and efficient service.', products_services='["Avaya IP Office Sales and Service","structured cabling","sip provider","telecommunications equipment support"]', keywords='Avaya IP Office, telecommunications equipment, structured cabling, sip provider, technical support, VOIP', enrichment_status='completed', enrichment_date='2025-08-24T11:01:48.345Z', enrichment_source='firecrawl', business_attributes='{"locally_owned":true,"specialty_focus":"Telecommunications equipment and systems support"}' WHERE id='1cd53b44-25c2-4dee-823a-3a574c8faa3f';
UPDATE businesses SET primary_category='retail_shopping', subcategory='electronics', business_description='United Fire Equipment Co. is a comprehensive fire safety and protection equipment provider based in Tucson, Arizona. They serve a wide range of customers, including fire departments, industrial facilities, and restaurants, by offering a variety of fire safety products and services. Their offerings include fire extinguishers, fire suppression and detection systems, fire truck parts, personal protective equipment, safety products, and uniforms. They also provide fire protection services such as extinguisher inspections, fire alarm inspections, kitchen inspections, and sprinkler inspections. They distinguish themselves by offering a wide range of products from various brands and providing comprehensive fire safety services.', products_services='["Fire Department Products","Fire Extinguishers","Fire Suppression & Detection Systems","Fire Truck Parts","Personal Protective Equipment","Safety Products","Uniforms","Fire Protection Services"]', keywords='fire safety, fire equipment, fire extinguishers, fire suppression systems, fire detection systems, personal protective equipment, fire protection services', enrichment_status='completed', enrichment_date='2025-08-24T10:47:13.808Z', enrichment_source='firecrawl', business_attributes='{"locally_owned":true,"specialty_focus":"Fire Safety and Protection Equipment"}' WHERE id='153573f6-a7a6-4d3e-bc6a-b932963c3f3c';
